<script setup>
import { onMounted, ref } from 'vue'
import { RouterLink, useRouter } from 'vue-router'
import { authState, clearSession } from '../services/authApi'
import { deleteEventComment, getModerationComments, getStaffTopUps, reviewTopUp } from '../services/communityApi'

const router = useRouter(); const topUps = ref([]); const comments = ref([]); const status = ref('Pending'); const error = ref(''); const notice = ref('')
const load = async () => { error.value = ''; try { [topUps.value, comments.value] = await Promise.all([getStaffTopUps(status.value), getModerationComments()]) } catch (e) { error.value = e.message } }
const review = async (item, nextStatus) => { const note = globalThis.prompt(nextStatus === 'Approved' ? 'Ghi chú duyệt (tùy chọn)' : 'Lý do từ chối') ?? ''; try { await reviewTopUp(item.id, nextStatus, note); notice.value = `Đã xử lý yêu cầu #${item.id}.`; await load() } catch (e) { error.value = e.message } }
const removeComment = async item => { if (!globalThis.confirm('Xóa bình luận không hợp lệ này?')) return; try { await deleteEventComment(item.id); comments.value = comments.value.filter(x => x.id !== item.id) } catch (e) { error.value = e.message } }
const logout = async () => { clearSession(); await router.replace('/') }; const money = v => Number(v).toLocaleString('vi-VN') + 'đ'; const date = v => new Date(v).toLocaleString('vi-VN')
onMounted(load)
</script>
<template><main class="min-h-screen px-4 py-16 sm:px-6 sm:py-24"><div class="mx-auto max-w-7xl"><header class="mb-8 flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p class="text-xs font-black uppercase tracking-[0.24em] text-cyan-400">Trang nhân viên</p><h1 class="mt-2 text-4xl font-black text-white">Kiểm duyệt & Nạp thẻ</h1><p class="mt-2 text-gray-400">{{ authState.session?.displayName }} · {{ authState.session?.role }}</p></div><div class="flex gap-3"><RouterLink to="/forum" class="rounded-xl border border-white/10 px-4 py-2 text-sm font-bold text-white">Mở diễn đàn</RouterLink><button class="rounded-xl border border-white/10 px-4 py-2 text-sm font-bold text-gray-300" @click="logout">Đăng xuất</button></div></header><p v-if="notice" class="mb-4 rounded-xl bg-emerald-500/10 p-3 text-emerald-300">{{ notice }}</p><p v-if="error" class="mb-4 rounded-xl bg-red-500/10 p-3 text-red-300">{{ error }}</p><div class="grid gap-6 xl:grid-cols-2"><section class="rounded-2xl border border-white/10 bg-[#0b0d13] p-5"><div class="flex items-center justify-between gap-3"><h2 class="text-xl font-black text-white">Yêu cầu nạp</h2><select v-model="status" class="rounded-lg border border-white/10 bg-black/30 px-3 py-2 text-sm text-white" @change="load"><option>Pending</option><option>Approved</option><option>Rejected</option><option value="">Tất cả</option></select></div><div class="mt-4 space-y-3"><article v-for="item in topUps" :key="item.id" class="rounded-xl border border-white/5 bg-black/20 p-4"><div class="flex justify-between gap-3"><div><strong class="text-white">#{{ item.id }} · {{ item.displayName }}</strong><p class="mt-1 text-sm text-gray-400">{{ money(item.amount) }} · {{ item.provider }} · {{ item.referenceCode }}</p></div><span class="text-xs font-black text-amber-300">{{ item.status }}</span></div><div v-if="item.status === 'Pending'" class="mt-4 flex gap-2"><button class="rounded-lg bg-emerald-500 px-3 py-2 text-xs font-black text-black" @click="review(item, 'Approved')">Duyệt</button><button class="rounded-lg bg-red-500 px-3 py-2 text-xs font-black text-white" @click="review(item, 'Rejected')">Từ chối</button></div></article><p v-if="topUps.length === 0" class="py-8 text-center text-gray-500">Không có yêu cầu.</p></div></section><section class="rounded-2xl border border-white/10 bg-[#0b0d13] p-5"><h2 class="text-xl font-black text-white">Bình luận gần đây</h2><div class="mt-4 max-h-[650px] space-y-3 overflow-y-auto pr-1"><article v-for="item in comments" :key="item.id" class="rounded-xl border border-white/5 bg-black/20 p-4"><div class="flex justify-between gap-3"><div><strong class="text-white">{{ item.displayName }}</strong><RouterLink :to="`/events/${item.eventId}`" class="ml-2 text-xs text-opm-gold">Xem sự kiện</RouterLink></div><button class="text-xs font-bold text-red-400" @click="removeComment(item)">Xóa</button></div><p class="mt-2 text-sm leading-6 text-gray-300">{{ item.content }}</p><time class="mt-2 block text-[11px] text-gray-600">{{ date(item.createdAt) }}</time></article><p v-if="comments.length === 0" class="py-8 text-center text-gray-500">Chưa có bình luận.</p></div></section></div></div></main></template>
